const items = $input.all();
if (items.length === 0 || !items[0].json.keyword) {
  return [{ json: { skip: true, message: 'No decaying pages found this month' } }];
}
return items;

const wpData = $input.item.json;
const decayData = $('Check for Decay').item.json;

if (decayData.skip) return [{ json: decayData }];

const post = Array.isArray(wpData) ? wpData[0] : null;
const contentSnippet = post?.content?.rendered
  ? post.content.rendered.replace(/<[^>]+>/g, '').slice(0, 2000)
  : 'Content not fetched';

const prompt = `This page has dropped ${decayData.position_drop} positions in Google over 90 days.
Keyword: "${decayData.keyword}"
Current position: ${decayData.current_pos}
Previous position (90d ago): ${decayData.pos_90_days_ago}

Current page content snippet:
${contentSnippet}

Provide 3 specific, actionable recommendations to recover this page's ranking.
Focus on: content freshness, keyword depth, E-E-A-T signals.
Return as JSON: { "recommendations": [{"action": "...", "why": "...", "priority": "high/medium/low"}] }`;

return [{ json: { ...decayData, postId: post?.id, claudePrompt: prompt } }];

const claudeData = $input.item.json;
const inputData = $('Build Refresh Prompt').item.json;

if (inputData.skip) return [{ json: inputData }];

let recs = [];
try {
  const rawText = claudeData.content?.[0]?.text || '{}';
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  const parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
  recs = parsed.recommendations || [];
} catch(e) {}

return [{ json: {
  projectName: inputData.project_name,
  keyword: inputData.keyword,
  currentPos: inputData.current_pos,
  positionDrop: inputData.position_drop,
  urlRanking: inputData.url_ranking,
  recommendations: recs
}}];

const allItems = $input.all();
const decayPages = allItems.map(i => i.json).filter(d => !d.skip);

if (decayPages.length === 0) {
  return [{ json: { summaryText: '✅ *Content Decay Report — No decaying pages found this month!*' } }];
}

let msg = `*📉 Monthly Content Decay Report — ${new Date().toDateString()}*\n\n`;
msg += `${decayPages.length} pages showing decay (5+ position drop over 90 days):\n\n`;

decayPages.forEach(d => {
  msg += `*${d.projectName}* — "${d.keyword}"\n`;
  msg += `  Dropped: #${d.currentPos - d.positionDrop} → #${d.currentPos} (${d.positionDrop} positions)\n`;
  if (d.recommendations?.length > 0) {
    msg += `  Top fix: ${d.recommendations[0].action}\n`;
  }
  msg += '\n';
});

msg += '_Refresh recommendations stored in seo_opportunities table._';

return [{ json: { summaryText: msg } }];
